# Management-group-scoped Deployment Stack with deny settings
# MG-scoped stacks protect resources across ALL subscriptions in the MG.
# Use for platform governance — policies, role definitions, MG-level role assignments.

BREAK_GLASS_OID='<break-glass-oid>'
PIPELINE_SP_OID='<pipeline-sp-oid>'

# Create MG-scoped stack protecting platform governance resources
az stack mg create \
  --name 'platform-governance' \
  --management-group-id 'alz' \
  --location eastus \
  --template-file platform_governance.bicep \
  --parameters @platform_governance.parameters.json \
  --deny-settings-mode DenyDelete \
  --deny-settings-apply-to-child-scopes \
  --deny-settings-excluded-principals $BREAK_GLASS_OID $PIPELINE_SP_OID \
  --action-on-unmanage detachAll

# MG-scoped stack Bicep example — protects policy definitions and assignments at MG scope
cat << 'EOF' > platform_governance.bicep
targetScope = 'managementGroup'

param policyAssignmentDisplayName string = 'Require HTTPS for Storage'

// Policy definition at MG scope (custom definition protected by stack deny)
resource requireHttpsPolicy 'Microsoft.Authorization/policyDefinitions@2021-06-01' = {
  name: 'require-https-storage'
  properties: {
    policyType: 'Custom'
    mode: 'All'
    displayName: policyAssignmentDisplayName
    policyRule: {
      if: {
        allOf: [
          { field: 'type', equals: 'Microsoft.Storage/storageAccounts' }
          { field: 'Microsoft.Storage/storageAccounts/supportsHttpsTrafficOnly', notEquals: true }
        ]
      }
      then: { effect: 'deny' }
    }
  }
}

// Policy assignment at MG scope — also protected by stack deny
resource policyAssignment 'Microsoft.Authorization/policyAssignments@2022-06-01' = {
  name: 'require-https-storage-assign'
  properties: {
    displayName: policyAssignmentDisplayName
    policyDefinitionId: requireHttpsPolicy.id
    enforcementMode: 'Default'
  }
}
EOF

# Show MG-scoped stack and managed resources
az stack mg show \
  --name 'platform-governance' \
  --management-group-id 'alz' \
  --query '{Status:provisioningState, DenyMode:denySettings.mode, Resources:length(resources)}' \
  -o json
